/* Global reset & box sizing */
* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
  background-color: #0b0f1a;
  color: white;
}

/* Base page styles */
body {
  font-family: Arial, sans-serif;
  background-color: #0b0f1a;
  background: radial-gradient(#0b0f1a, #0b0f1a, #0b0f1a );
  padding: 20px;

}

/* Centered container */
.container {
  max-width: 1200px;
  margin: 0 auto;
  background-color: #0b0f1a;
}

/* Header */
.site-header {
  display: flex;
  align-items: center;
  justify-content: center;
  padding-top: 20px;
  padding-bottom: 20px;
  margin-bottom: 20px;
}

h1 {
  font-family: Verdana, sans-serif;
  font-weight: bold;
  color: #ffffff;
}

/* Logo */
.logo {
  width: 140px;
  margin-right: 15px;
}

/* Date‐picker & button row */
.filters {
  display: flex;
  flex-direction: column;
  gap: 10px;
  justify-content: center;
  margin-bottom: 20px;
  padding: 0 20px;
}

/* Inputs and buttons */
input[type="date"],
button {
  background-color: #ffffff;
  font-family: Arial, sans-serif;
  font-weight: normal;
  color: #0b0f1a;
  padding: 10px 15px;
  border: 1px solid rgba(228, 0, 43, 0.4);
  border-radius: 4px;
  font-size: 16px;
  line-height: 1.4;
  width: 100%;
}

/* Button specific */
button {
  background-color: rgba(228, 0, 43, 0.7);
  color: #ffffff;
  cursor: pointer;
}
button:hover {
  background-color: rgba(135, 0, 25, 0.8);
}

/* Stack horizontally on wider screens */


/* Gallery flex container */
.gallery {
  display: flex;
  flex-wrap: wrap;
  gap: 20px;
  padding: 20px;
  justify-content: center;
}

/* Gallery items */
.gallery-item {
  flex: 1 1 100%;  /* full width by default */
  min-width: 280px;
  /*max-width: 500px;*/
  /*background: white;*/
  padding: 10px;
  border-radius: 8px;
  box-shadow: 0 2px 5px rgba(0,0,0,0.1);
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

/* Three columns on wider screens */
/*@media (max-width: 1000px) {*/
/*  .gallery-item {*/
/*    flex: 0 1 31%;*/
/*  }*/


/*}*/

.gallery-item img {
  width: 100%;
  height: 200px;
  object-fit: contain;
  border-radius: 4px;
}

.gallery-item p {
  margin-top: 10px;
  padding: 5px;
  font-size: 14px;
}

/* Placeholder content */
.placeholder {
  flex: 1 1 100%;
  text-align: center;
  padding: 40px;
  color: #666;
}

.placeholder-icon {
  font-size: 48px;
  margin-bottom: 20px;
}

.photoCard {
  /*align-self: center;*/
  padding: 20px;

  /*border-radius: 10px;*/
  /*padding-top: 2rem;*/

}
.mediaClass {
  /*max-height: 350px;*/
}

/* Ensure all cards have a consistent size and maintain aspect ratio */
.card {
    height: 350px; /* Set a fixed height for all cards */
    display: flex;
    /*flex-direction: column;*/
    /*justify-content: space-between;*/
    transform: scale(1);
}
.card:hover {
  box-shadow: 0 4px 8px rgba(0,0,0,0.2);
  transform: scale(1.02)

}

.card-img-top {
    height: 75%; /* Reserve 80% of the card height for the image */
    object-fit: cover; /* Scale image to fill the space while maintaining aspect ratio */
}

.card-body {
    height: 30%; /* Reserve 20% of the card height for the body */
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    text-align: center;
}
.close{
  width: 120px;
}
.modal-body p {
  margin-top: 20px;
  text-align: left;
}
.modal {
  background-color: rgba(0, 0, 0, 0.5);

}

@media (max-width: 600px) {
  .card-title{
    font-size: 13px;
  }
  .card-text {
    font-size: 12px;
  }
}

